#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long cntA=0,cntB=0,cntAB=0,cntO=0;
        char s[4];
        for(int i=0;i<N;i++){
            scanf("%s", s);
            if(strcmp(s,"A")==0) cntA++;
            else if(strcmp(s,"B")==0) cntB++;
            else if(strcmp(s,"AB")==0) cntAB++;
            else if(strcmp(s,"O")==0) cntO++;
        }
        long long ans = cntO + cntAB + (cntA>cntB?cntA:cntB);
        printf("%lld\n", ans);
    }
    return 0;
}

