import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        cntA = cntB = cntAB = cntO = 0
        for _ in range(N):
            s = next(it)
            if s == 'A':
                cntA += 1
            elif s == 'B':
                cntB += 1
            elif s == 'AB':
                cntAB += 1
            else:  # O
                cntO += 1
        ans = cntO + cntAB + max(cntA, cntB)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

